function Cart({ items }) {
  return (
    <div>
      <h2>Cart</h2>
      {items.length && <p>You have items!</p>}
    </div>
  );
}

function Spoiler({ text }) {
  const [revealed, setRevealed] = useState(false);
  return (
    <div>
      {revealed ? <p>{text}</p> : <p>Hidden</p>}
      <button onClick={() => setRevealed(prev => !prev)}>
        {revealed ? 'Hide' : 'Reveal'}
      </button>
    </div>
  );
}
